namespace sv_94f2706444b24cdb987d3fd720ceef81.Services;

public enum Theme
{
    Light,
    Dark,
    System
}

/// <summary>
/// Scoped service holding per-circuit theme state.
/// Any component can inject this to read/write theme values.
/// Subscribers re-render automatically via the OnChange event.
/// </summary>
public class ThemeState
{
    private Theme _theme = Theme.Light;
    private string _accentColor = "#0d6efd";

    public Theme Theme
    {
        get => _theme;
        set
        {
            if (_theme == value) return;
            _theme = value;
            NotifyChanged();
        }
    }

    public string AccentColor
    {
        get => _accentColor;
        set
        {
            if (_accentColor == value) return;
            _accentColor = value;
            NotifyChanged();
        }
    }

    public event Action? OnChange;

    private void NotifyChanged() => OnChange?.Invoke();
}

@implements IDisposable
@inject ThemeState ThemeState

<span class="theme-indicator" style="color: @ThemeState.AccentColor;" title="Current theme">
    @GetThemeIcon() @ThemeState.Theme
</span>

@code {
    protected override void OnInitialized()
    {
        ThemeState.OnChange += StateHasChanged;
    }

    private string GetThemeIcon() => ThemeState.Theme switch
    {
        Theme.Light => "☀️",
        Theme.Dark => "🌙",
        Theme.System => "💻",
        _ => "☀️"
    };

    public void Dispose()
    {
        ThemeState.OnChange -= StateHasChanged;
    }
}

@implements IDisposable
@inject ThemeState ThemeState

<div class="theme-toggle">
    <button class="btn btn-sm btn-outline-secondary" @onclick="CycleTheme"
            style="border-color: @ThemeState.AccentColor;">
        @GetThemeIcon() @ThemeState.Theme
    </button>
</div>

@code {
    private void CycleTheme()
    {
        ThemeState.Theme = ThemeState.Theme switch
        {
            Theme.Light => Theme.Dark,
            Theme.Dark => Theme.System,
            Theme.System => Theme.Light,
            _ => Theme.Light
        };
    }

    private string GetThemeIcon() => ThemeState.Theme switch
    {
        Theme.Light => "☀️",
        Theme.Dark => "🌙",
        Theme.System => "💻",
        _ => "☀️"
    };

    protected override void OnInitialized()
    {
        ThemeState.OnChange += StateHasChanged;
    }

    public void Dispose()
    {
        ThemeState.OnChange -= StateHasChanged;
    }
}

@page "/settings"
@rendermode InteractiveServer
@implements IDisposable
@inject ThemeState ThemeState

<PageTitle>Settings</PageTitle>

<h1>User Preferences</h1>

<div class="card p-4" style="max-width: 500px; border-color: @ThemeState.AccentColor;">
    <h4>Theme</h4>
    <div class="btn-group mb-3" role="group">
        @foreach (var theme in Enum.GetValues<Theme>())
        {
            var isActive = ThemeState.Theme == theme;
            <button class="btn @(isActive ? "btn-primary" : "btn-outline-primary")"
                    style="@(isActive ? $"background-color: {ThemeState.AccentColor}; border-color: {ThemeState.AccentColor};" : "")"
                    @onclick="() => ThemeState.Theme = theme">
                @theme
            </button>
        }
    </div>

    <h4>Accent Color</h4>
    <div class="d-flex align-items-center gap-3 mb-3">
        <input type="color" class="form-control form-control-color"
               value="@ThemeState.AccentColor"
               @onchange="OnAccentColorChanged" />
        <span>@ThemeState.AccentColor</span>
    </div>

    <ThemeToggle />
</div>

@code {
    protected override void OnInitialized()
    {
        ThemeState.OnChange += StateHasChanged;
    }

    private void OnAccentColorChanged(ChangeEventArgs e)
    {
        ThemeState.AccentColor = e.Value?.ToString() ?? "#0d6efd";
    }

    public void Dispose()
    {
        ThemeState.OnChange -= StateHasChanged;
    }
}

